from flask import Flask, render_template, request, redirect, url_for, session
import pyotp
from werkzeug.security import generate_password_hash, check_password_hash
import sqlite3

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# SQLite DB setup
conn = sqlite3.connect('users.db')
cursor = conn.cursor()
cursor.execute('''
    CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT NOT NULL,
        password TEXT NOT NULL,
        mfa_secret TEXT NOT NULL
    );
''')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        cursor.execute('SELECT * FROM users WHERE username=? AND password=?',
                       (username, generate_password_hash(password)))
        user = cursor.fetchone()

        if user:
            session['user_id'] = user[0]
            return redirect(url_for('verify_mfa'))
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET'])
def verify_mfa():
    user_id = session.get('user_id')
    if not user_id:
        return 'You must login first.', 401

    mfa_secret = get_user_mfa_secret(user_id)
    totp = pyotp.TOTP(mfa_secret).now()
    return render_template('verify_mfa.html', totp=totp)

@app.route('/verify-mfa-code', methods=['POST'])
def verify_mfa_code():
    user_id = session.get('user_id')
    if not user_id:
        return 'You must login first.', 401

    mfa_secret = get_user_mfa_secret(user_id)
    totp = pyotp.TOTP(mfa_secret).now()

